// 1. Capture the incoming data from the user (Webhook)
const body = $input.first().json.body;

// 2. ID GENERATOR: Create a unique ID for this specific interaction.
// This allows us to track this query across n8n, the AI logs, and Airtable.
const request_id = body.request_id || (() => {
    return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
        const r = Math.random() * 16 | 0;
        return (c === 'x' ? r : (r & 0x3 | 0x8)).toString(16);
    });
})();

// 3. Extract core fields for processing
const user_query = body.user_query;
const expected_intent = body.expected_intent || null; // Used for automated testing
const now = Date.now();

// 4. PREPARE PAYLOAD: Create the standard object used by the whole workflow
return [{
    json: {
        request_id,
        user_query,
        expected_intent,
        timestamp: new Date(now).toISOString(),
        webhook_received_time: now,  // Used to calculate total speed
        router_start_time: now        // Used to calculate AI Thinking speed
    }
}];

