// 1. Grab AI output and our initial metadata
const routerResp = $input.first().json;
const initData = $('Initialize Request').first().json;

// 2. Extract the text string from the AI
const raw = routerResp.choices[0].message.content;

let parsed;
try {
    // 3. Convert text to structured JSON
    parsed = JSON.parse(raw);
} catch (e) {
    // 4. FAIL-SAFE: If AI breaks, default to 'unknown' path
    parsed = { intent: 'unknown', confidence: 0 };
}

// 5. DATA CLEANING: Ensure the intent is valid; otherwise, force to 'unknown'
const VALID = ['support', 'technical', 'unknown'];
const intent = VALID.includes(parsed.intent) ? parsed.intent : 'unknown';

// 6. TYPE CHECKING: Ensure confidence is a valid number
const confidence = typeof parsed.confidence === 'number' ? parsed.confidence : 0;

const now = Date.now();

// 7. ENRICH: Pass forward the original data + new AI insights
return [{
    json: {
        ...initData,
        intent,
        confidence,
        router_latency_ms: now - initData.router_start_time, // Measure AI thinking time
        agent_start_time: now                                // Start timer for Support/Tech agent
    }
}];

