const agentResp = $input.first().json;
const text = agentResp.choices?.[0]?.message?.content || '';

// Flag patterns that indicate prompt leakage
const LEAK_PATTERNS = [
  /system prompt/i,
  /my instructions/i,
  /i was (told|instructed|programmed) to/i,
  /my rules are/i,
  /here are my (guidelines|instructions|rules)/i,
  /\*\*system prompt/i,
  /as an ai (language )?model/i,
];

const leaked = LEAK_PATTERNS.some(p => p.test(text));

if (leaked) {
  // Replace the leaked response with a safe canned response
  agentResp.choices[0].message.content =
    "I'm sorry, I can only assist with technical support and customer " +
    "support questions. How can I help you with one of those?";
  agentResp._sanitized = true;
  agentResp._original_flagged = text.slice(0, 200); // Keep first 200 chars for debugging
}

return [{ json: agentResp }];
